var conn = require("./db");

module.exports = {

    dashboard(){

        return new Promise((resolve, reject) => {

            conn.query(`

                SELECT
                (SELECT COUNT(*) FROM tb_contacts) AS nrcontacts,
                (SELECT COUNT(*) FROM tb_menus) AS nrmenus,
                (SELECT COUNT(*) FROM tb_reservations) AS nrreservations,
                (SELECT COUNT(*) FROM tb_users) AS nrusers;

            `, (err, results) => {

                if(err){

                    reject(err);

                } else {

                    resolve(results[0]);

                }

            });

        });

    },

    getParams(req, params){

        return Object.assign({}, {
            menus: req.menus,
            //user: req.session.user
        }, params);

    },

    getMenus(req){

        let menus = [
            {
                text:'Tela Inicial',
                href:'/admin/',
                icon:'home',
                active:false
            },

            {
                text:'Menu',
                href:'/admin/menus',
                icon:'cutlery',
                active:false
            },

            {
                text:'Reservas',
                href:'/admin/reservations',
                icon:'calendar-check-o',
                active:false
            },

            {
                text:'Contatos',
                href:'/admin/contacts',
                icon:'comments',
                active:false
            },

            {
                text:'Usuários',
                href:'/admin/users',
                icon:'users',
                active:false
            },

            {
                text:'E-mails',
                href:'/admin/emails',
                icon:'envelope',
                active:false
            }
        ];

        menus.map(menu => {

            if(menu.href === `/admin${req.url}`) menu.active = true;

        });

        return menus;

    }

};

var conn = require('./db');

module.exports = {

    render(req, res, error){

        res.render('admin/login', {

            body: req.body,
            error

        });

    },

    login(email, password){

        return new Promise((resolve, reject)=>{

            conn.query(`

                SELECT * FROM tb_users WHERE email = ?

            `, [
                email
            ], (err, results)=>{

                if(err){

                    reject(err);

                } else{

                    if(!results.length > 0){

                        reject('Usuário ou senha incorretos.');

                    } else {

                        let row = results[0];

                        if(row.password !== password){

                            reject('Usuário ou senha incorretos.');

                        } else {

                            resolve(row);

                        }

                    }                   

                }

            });

        });

    }, 

